-- Policies

-- libraries
CREATE POLICY libraries_select ON public.libraries FOR SELECT TO authenticated USING (id = ANY (get_user_library_ids()));
CREATE POLICY libraries_insert ON public.libraries FOR INSERT TO authenticated WITH CHECK (owner_id = auth.uid());
CREATE POLICY libraries_update ON public.libraries FOR UPDATE TO authenticated USING (owner_id = auth.uid());
CREATE POLICY libraries_delete ON public.libraries FOR DELETE TO authenticated USING (owner_id = auth.uid());

-- students
CREATE POLICY students_select ON public.students FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY students_insert ON public.students FOR INSERT TO authenticated WITH CHECK (library_id = ANY (get_user_library_ids()));
CREATE POLICY students_update ON public.students FOR UPDATE TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY students_delete ON public.students FOR DELETE TO authenticated USING (is_library_owner(library_id));

-- seats
CREATE POLICY seats_select ON public.seats FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY seats_modify ON public.seats FOR ALL TO authenticated USING (is_library_owner(library_id));

-- lockers
CREATE POLICY lockers_select ON public.lockers FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY lockers_modify ON public.lockers FOR ALL TO authenticated USING (is_library_owner(library_id));

-- shifts
CREATE POLICY shifts_select ON public.shifts FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY shifts_modify ON public.shifts FOR ALL TO authenticated USING (is_library_owner(library_id));

-- combo_plans
CREATE POLICY combo_plans_select ON public.combo_plans FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY combo_plans_modify ON public.combo_plans FOR ALL TO authenticated USING (is_library_owner(library_id));

-- locker_policies
CREATE POLICY locker_policies_select ON public.locker_policies FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY locker_policies_modify ON public.locker_policies FOR ALL TO authenticated USING (is_library_owner(library_id));

-- staff
CREATE POLICY staff_select ON public.staff FOR SELECT TO authenticated USING (library_ids && get_user_library_ids());

-- notifications
CREATE POLICY notifications_select ON public.notifications FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY notifications_update ON public.notifications FOR UPDATE TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY "staff can insert notifications" ON public.notifications FOR INSERT TO public WITH CHECK (library_id IN ( SELECT unnest(staff.library_ids) AS unnest FROM staff WHERE (staff.user_id = auth.uid())));

-- payment_records
CREATE POLICY payment_records_select ON public.payment_records FOR SELECT TO authenticated USING (library_id = ANY (get_user_library_ids()));
CREATE POLICY payment_records_insert ON public.payment_records FOR INSERT TO authenticated WITH CHECK (library_id = ANY (get_user_library_ids()));

-- pricing_config
CREATE POLICY pricing_config_select ON public.pricing_config FOR SELECT TO authenticated USING (true);

-- contact_messages
CREATE POLICY contact_messages_insert ON public.contact_messages FOR INSERT TO anon, authenticated WITH CHECK (true);

-- student_seat_shifts
CREATE POLICY "staff can insert seat shifts" ON public.student_seat_shifts FOR INSERT TO public WITH CHECK (seat_id IN ( SELECT seats.id FROM seats WHERE (seats.library_id IN ( SELECT unnest(staff.library_ids) AS unnest FROM staff WHERE (staff.user_id = auth.uid())))));
CREATE POLICY "staff can select seat shifts" ON public.student_seat_shifts FOR SELECT TO public USING (seat_id IN ( SELECT seats.id FROM seats WHERE (seats.library_id IN ( SELECT unnest(staff.library_ids) AS unnest FROM staff WHERE (staff.user_id = auth.uid())))));
CREATE POLICY "staff can delete seat shifts" ON public.student_seat_shifts FOR DELETE TO public USING (seat_id IN ( SELECT seats.id FROM seats WHERE (seats.library_id IN ( SELECT unnest(staff.library_ids) AS unnest FROM staff WHERE (staff.user_id = auth.uid())))));

-- financial_events
CREATE POLICY "staff can insert financial events" ON public.financial_events FOR INSERT TO public WITH CHECK (library_id IN ( SELECT unnest(staff.library_ids) AS unnest FROM staff WHERE (staff.user_id = auth.uid())));
CREATE POLICY "staff can select financial events" ON public.financial_events FOR SELECT TO public USING (library_id IN ( SELECT unnest(staff.library_ids) AS unnest FROM staff WHERE (staff.user_id = auth.uid())));
